using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummaryService _summaryService;

    public SummarizeController(DocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);
        int originalWordCount = request.DocumentText.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;
        int summaryWordCount = summary.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = originalWordCount,
            SummaryWordCount = summaryWordCount,
        });
    }
}

